import{_ as s,c as a,o as n,a as l}from"./app.09261a68.js";const h=JSON.parse('{"title":"Minikube集群安装","description":"","frontmatter":{"date":"2022-12-31T00:00:00.000Z"},"headers":[{"level":2,"title":"搭建环境","slug":"搭建环境","link":"#搭建环境","children":[]},{"level":2,"title":"安装Kubectl","slug":"安装kubectl","link":"#安装kubectl","children":[]},{"level":2,"title":"安装Minikube","slug":"安装minikube","link":"#安装minikube","children":[]},{"level":2,"title":"使用Minikube启动集群","slug":"使用minikube启动集群","link":"#使用minikube启动集群","children":[]},{"level":2,"title":"查看集群状态","slug":"查看集群状态","link":"#查看集群状态","children":[]},{"level":2,"title":"配置Kubeconfig","slug":"配置kubeconfig","link":"#配置kubeconfig","children":[]},{"level":2,"title":"可视化界面","slug":"可视化界面","link":"#可视化界面","children":[]}],"relativePath":"zh/cloud-native/kubernetes/installation/minikube.md"}'),e={name:"zh/cloud-native/kubernetes/installation/minikube.md"},o=l(`<h1 id="minikube集群安装" tabindex="-1">Minikube集群安装 <a class="header-anchor" href="#minikube集群安装" aria-hidden="true">#</a></h1><p>Minikube是单节点的Kubernetes环境，常用于学习使用或作为开发环境。</p><h2 id="搭建环境" tabindex="-1">搭建环境 <a class="header-anchor" href="#搭建环境" aria-hidden="true">#</a></h2><p>服务器信息和基础环境如下：</p><ul><li>OS: Linux</li><li>Kubectl: v1.22.3</li><li>Minikube: v1.24.0</li><li>Golang: 1.15.15</li><li>Docker: 1.41 (<a href="/zh/tools/docker.html">Docker安装</a>)</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果使用中国境内网络，为避免网络影响，可以设置GOPROXY为以下任意一个：</p><ul><li>export GOPROXY=&quot;<a href="https://proxy.golang.org" target="_blank" rel="noreferrer">https://proxy.golang.org</a>,direct&quot;</li><li>export GOPROXY=&quot;<a href="https://goproxy.cn" target="_blank" rel="noreferrer">https://goproxy.cn</a>&quot;</li></ul></div><h2 id="安装kubectl" tabindex="-1">安装Kubectl <a class="header-anchor" href="#安装kubectl" aria-hidden="true">#</a></h2><ul><li><strong>步骤一</strong> 下载二进制文件</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-LO</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://storage.googleapis.com/kubernetes-release/release/</span><span style="color:#89DDFF;">$(</span><span style="color:#FFCB6B;">curl</span><span style="color:#C3E88D;"> -s https://storage.googleapis.com/kubernetes-release/release/stable.txt</span><span style="color:#89DDFF;">)</span><span style="color:#C3E88D;">/bin/linux/amd64/kubectl</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤二</strong> 修改二进制文件权限及路径</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">chmod</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+x</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubectl</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">mv</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">./kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/usr/local/bin/kubectl</span></span>
<span class="line"></span></code></pre></div><h2 id="安装minikube" tabindex="-1">安装Minikube <a class="header-anchor" href="#安装minikube" aria-hidden="true">#</a></h2><ul><li><strong>步骤一</strong> 下载二进制文件</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-Lo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">minikube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://storage.googleapis.com/minikube/releases/latest/minikube-linux-amd64</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤二</strong> 修改二进制文件权限及路径</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">chmod</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+x</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">minikube</span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">minikube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/usr/local/bin/</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤二</strong> 安装依赖工具<code>conntrack</code></li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">yum</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">conntrack</span></span>
<span class="line"></span></code></pre></div><h2 id="使用minikube启动集群" tabindex="-1">使用Minikube启动集群 <a class="header-anchor" href="#使用minikube启动集群" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">minikube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">start</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--vm-driver=none</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--image-repository=registry.cn-hangzhou.aliyuncs.com/google_containers</span></span>
<span class="line"></span></code></pre></div><p>启动参数说明：</p><ul><li>--vm-driver: 虚拟机驱动，如果使用本地服务器环境启动，设置为node即可；</li><li>--image-repository: 指定镜像仓库源，主要用于中国网络/私有网络无法访问google镜像的场景；</li><li>--kubernetes-version: 指定Kubernetes版本，如&quot;v1.18.20&quot;；</li></ul><h2 id="查看集群状态" tabindex="-1">查看集群状态 <a class="header-anchor" href="#查看集群状态" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">minikube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">status</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">## 健康的集群状态示例如下：</span></span>
<span class="line"><span style="color:#FFCB6B;">minikube</span></span>
<span class="line"><span style="color:#82AAFF;">type</span><span style="color:#FFCB6B;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Control</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Plane</span></span>
<span class="line"><span style="color:#FFCB6B;">host:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Running</span></span>
<span class="line"><span style="color:#FFCB6B;">kubelet:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Running</span></span>
<span class="line"><span style="color:#FFCB6B;">apiserver:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Running</span></span>
<span class="line"><span style="color:#FFCB6B;">kubeconfig:</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">Configured</span></span>
<span class="line"></span></code></pre></div><h2 id="配置kubeconfig" tabindex="-1">配置Kubeconfig <a class="header-anchor" href="#配置kubeconfig" aria-hidden="true">#</a></h2><p>配置<code>Kubeconfig</code>,方可使用<code>Kubectl</code>指令直接操作Kubernetes集群：</p><ul><li><strong>步骤一</strong> 修改二进制文件权限及路径</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># USER: 操作用户的名称，取自环境变量$USER即可</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># HOME: 操作用户的HOME路径，取自环境变量$HOME即可</span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">mv</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/root/.kube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/root/.minikube</span><span style="color:#A6ACCD;"> $HOME</span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">chown</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-R</span><span style="color:#A6ACCD;"> $USER $HOME</span><span style="color:#C3E88D;">/.kube</span><span style="color:#A6ACCD;"> $HOME</span><span style="color:#C3E88D;">/.minikube</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤二</strong> 修改文件<code>$HOME/.kube/config</code>,将其中的&quot;/root&quot;字段修改为<code>$HOME</code>对应路径。</li></ul><h2 id="可视化界面" tabindex="-1">可视化界面 <a class="header-anchor" href="#可视化界面" aria-hidden="true">#</a></h2><p><code>Minikube Dashboard</code>是使用Minikube启动的Kubernetes自带的可视化界面，可使用以下指令启动：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">minikube</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">dashboard</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--url</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 启动成功示例如下：</span></span>
<span class="line"><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> Verifying dashboard health ...</span></span>
<span class="line"><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> Launching proxy ...</span></span>
<span class="line"><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> Verifying proxy health ...</span></span>
<span class="line"><span style="color:#FFCB6B;">http://127.0.0.1:44509/api/v1/namespaces/kubernetes-dashboard/services/http:kubernetes-dashboard:/proxy/</span></span>
<span class="line"></span></code></pre></div><p>在安装Minikube的执行机上，使用本地浏览器中访问打印信息中的地址即可。</p><p>若需要在非安装机器上远程访问可视化界面，则可以使用<code>Kubectl</code>指令开启访问代理：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 指定执行机的8001号端口作为代理</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">nohup</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">proxy</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--port=8001</span><span style="color:#A6ACCD;">  </span><span style="color:#C3E88D;">--address=</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">0.0.0.0</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--accept-hosts=</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">^*$</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&gt;</span><span style="color:#C3E88D;">/dev/null</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">2&gt;&amp;1&amp;</span></span>
<span class="line"></span></code></pre></div><p>开启代理之后，即可使用以下地址远程访问可视化界面(ip为执行机ip)：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">http://</span><span style="color:#A6ACCD;">$ip</span><span style="color:#FFCB6B;">:8001/api/v1/namespaces/kubernetes-dashboard/services/http:kubernetes-dashboard:/proxy/</span></span>
<span class="line"></span></code></pre></div>`,37),p=[o];function t(c,i,r,C,u,y){return n(),a("div",null,p)}const b=s(e,[["render",t]]);export{h as __pageData,b as default};
